    27→//!     age_weight: 0.15,
    28→//!     labels_weight: 0.1,
    29→//!     ..Default::default()
    30→//! };
    31→//! let scorer = TaskScorer::with_config(config);
    32→//!
    33→//! // Calculate score for a bead
    34→//! let score = scorer.score(
