   152→/// A task scorer that calculates priority scores for beads.
   153→///
   154→/// The scorer uses a weighted formula combining multiple factors:
   155→/// - Priority level (P0-P4)
   156→/// - Number of tasks blocked by this task
   157→/// - Age of the task
   158→/// - Special labels (critical, urgent, important)
   159→#[derive(Debug, Clone)]
   160→pub struct TaskScorer {
   161→    config: ScoringConfig,
   162→}
   163→
   164→impl Default for TaskScorer {
   165→    fn default() -> Self {
   166→        Self::new()
   167→    }
   168→}
   169→
   170→impl TaskScorer {
   171→    /// Create a new scorer with default configuration.
   172→    pub fn new() -> Self {
   173→        Self {
   174→            config: ScoringConfig::default(),
   175→        }
   176→    }
   177→
   178→    /// Create a scorer with custom configuration.
   179→    pub fn with_config(config: ScoringConfig) -> Self {
   180→        Self { config }
   181→    }
   182→
   183→    /// Get the current configuration.
   184→    pub fn config(&self) -> &ScoringConfig {
   185→        &self.config
   186→    }
   187→
   188→    /// Calculate the total score for a task.
   189→    ///
   190→    /// # Arguments
   191→    ///
   192→    /// * `priority` - Priority level (0-4, where 0 is P0/critical)
   193→    /// * `dependent_count` - Number of other tasks blocked by this task
   194→    /// * `age_hours` - Optional age of the task in hours (None = 0)
   195→    /// * `labels` - Labels attached to the task
   196→    ///
   197→    /// # Returns
   198→    ///
   199→    /// A score from 0 to 100.
   200→    pub fn score(
   201→        &self,
   202→        priority: u8,
   203→        dependent_count: usize,
   204→        age_hours: Option<u32>,
   205→        labels: &[String],
   206→    ) -> u32 {
   207→        let priority_score = self.calculate_priority_score(priority);
   208→        let blockers_score = self.calculate_blockers_score(dependent_count);
   209→        let age_score = self.calculate_age_score(age_hours);
   210→        let labels_score = self.calculate_labels_score(labels);
   211→
   212→        // Apply weights and sum
   213→        let weighted_score = (priority_score as f64 * self.config.priority_weight)
   214→            + (blockers_score as f64 * self.config.blockers_weight)
   215→            + (age_score as f64 * self.config.age_weight)
   216→            + (labels_score as f64 * self.config.labels_weight);
   217→
   218→        // Clamp to 0-100
   219→        weighted_score.round().min(100.0).max(0.0) as u32
   220→    }
   221→
   222→    /// Calculate the priority component score.
   223→    ///
   224→    /// Per the specification:
   225→    /// - P0 = 40 points
   226→    /// - P1 = 32 points
   227→    /// - P2 = 24 points
   228→    /// - P3 = 16 points
   229→    /// - P4+ = 8 points
   230→    fn calculate_priority_score(&self, priority: u8) -> u32 {
   231→        match priority {
   232→            0 => 40, // P0 Critical
   233→            1 => 32, // P1 High
   234→            2 => 24, // P2 Medium
   235→            3 => 16, // P3 Low
   236→            _ => 8,  // P4+ Backlog
   237→        }
   238→    }
   239→
   240→    /// Calculate the blockers component score.
   241→    ///
   242→    /// 10 points per blocked task, max 30 points.
   243→    fn calculate_blockers_score(&self, dependent_count: usize) -> u32 {
   244→        let capped = (dependent_count as u32).min(self.config.max_blockers);
   245→        (capped * POINTS_PER_BLOCKER).min(MAX_BLOCKERS_POINTS)
   246→    }
   247→
   248→    /// Calculate the age component score.
   249→    ///
   250→    /// 1 point per hour since creation, max 20 points.
   251→    fn calculate_age_score(&self, age_hours: Option<u32>) -> u32 {
   252→        let hours = age_hours.unwrap_or(0).min(self.config.max_age_hours);
   253→        (hours * POINTS_PER_HOUR).min(MAX_AGE_POINTS)
   254→    }
   255→
   256→    /// Calculate the labels component score.
   257→    ///
   258→    /// Points for special labels:
   259→    /// - "critical" = 10 points
   260→    /// - "urgent" = 7 points
   261→    /// - "important" = 4 points
   262→    ///
   263→    /// Only the highest-value label is counted.
   264→    fn calculate_labels_score(&self, labels: &[String]) -> u32 {
   265→        let mut max_label_score = 0u32;
   266→
   267→        for label in labels {
   268→            let label_lower = label.to_lowercase();
   269→            let score = if label_lower == "critical" {
   270→                LABEL_CRITICAL_POINTS
   271→            } else if label_lower == "urgent" {
   272→                LABEL_URGENT_POINTS
   273→            } else if label_lower == "important" {
   274→                LABEL_IMPORTANT_POINTS
   275→            } else {
   276→                0
   277→            };
   278→            max_label_score = max_label_score.max(score);
   279→        }
   280→
   281→        max_label_score.min(MAX_LABELS_POINTS)
   282→    }
   283→
   284→    /// Parse age from a timestamp string.
   285→    ///
   286→    /// Accepts ISO 8601 format timestamps and calculates hours since creation.
   287→    pub fn parse_age_hours(created_at: &str) -> Option<u32> {
   288→        // Try parsing ISO 8601 timestamp
   289→        if let Ok(dt) = chrono::DateTime::parse_from_rfc3339(created_at) {
   290→            let now = chrono::Utc::now();
   291→            let duration = now.signed_duration_since(dt);
   292→            return Some(duration.num_hours().max(0) as u32);
   293→        }
   294→
   295→        // Try chrono's datetime parser for other formats
   296→        if let Ok(dt) = chrono::DateTime::parse_from_str(created_at, "%Y-%m-%d %H:%M:%S %:z") {
   297→            let now = chrono::Utc::now();
   298→            let duration = now.signed_duration_since(dt);
   299→            return Some(duration.num_hours().max(0) as u32);
   300→        }
   301→
   302→        // Try without timezone
   303→        if let Ok(dt) = chrono::NaiveDateTime::parse_from_str(created_at, "%Y-%m-%d %H:%M:%S") {
   304→            let now = chrono::Utc::now().naive_utc();
   305→            let duration = now.signed_duration_since(dt);
   306→            return Some(duration.num_hours().max(0) as u32);
   307→        }
   308→
   309→        None
   310→    }
   311→
   312→    /// Compare two tasks by score for sorting (highest first).
   313→    pub fn compare_by_score(
   314→        &self,
   315→        a_priority: u8,
   316→        a_dependents: usize,
   317→        a_age: Option<u32>,
   318→        a_labels: &[String],
   319→        b_priority: u8,
   320→        b_dependents: usize,
   321→        b_age: Option<u32>,
   322→        b_labels: &[String],
   323→    ) -> std::cmp::Ordering {
   324→        let score_a = self.score(a_priority, a_dependents, a_age, a_labels);
   325→        let score_b = self.score(b_priority, b_dependents, b_age, b_labels);
   326→
   327→        // Higher score comes first
   328→        score_b.cmp(&score_a)
   329→    }
   330→}
   331→
   332→/// A scored bead ready for display or sorting.
   333→#[derive(Debug, Clone)]
   334→pub struct ScoredBead {
   335→    /// The calculated score (0-100)
   336→    pub score: u32,
   337→    /// Breakdown of score components
   338→    pub components: ScoreComponents,
   339→}
   340→
   341→/// Breakdown of individual score components.
   342→#[derive(Debug, Clone, Default)]
   343→pub struct ScoreComponents {
   344→    /// Priority component score
   345→    pub priority: u32,
   346→    /// Blockers component score
   347→    pub blockers: u32,
   348→    /// Age component score
   349→    pub age: u32,
   350→    /// Labels component score
   351→    pub labels: u32,
   352→}
   353→
   354→impl TaskScorer {
   355→    /// Calculate a scored bead with component breakdown.
   356→    pub fn score_with_components(
   357→        &self,
   358→        priority: u8,
   359→        dependent_count: usize,
   360→        age_hours: Option<u32>,
   361→        labels: &[String],
   362→    ) -> ScoredBead {
   363→        let components = ScoreComponents {
