     1→//! Multi-model routing engine for task-to-model assignment.
     2→//!
     3→//! This module implements intelligent routing of tasks to appropriate AI models
     4→//! based on complexity, cost, availability, and subscription quotas.
     5→//!
     6→//! ## Overview
     7→//!
     8→//! The router uses a tiered approach:
     9→//! - **Premium**: claude-opus-4, o1, glm-5 (complex reasoning, architecture)
    10→//! - **Standard**: claude-sonnet-4, gpt-4, qwen-2.5 (typical coding tasks)
    11→//! - **Budget**: claude-haiku-4, gpt-3.5, deepseek-coder (simple edits, formatting)
    12→//!
    13→//! ## Routing Rules
    14→//!
    15→//! 1. Task complexity → Model tier mapping based on priority
    16→//! 2. Subscription quota check → Prefer use-or-lose tokens
    17→//! 3. Worker availability → Load balance across same tier
    18→//! 4. Fallback chain → Premium fails → Standard → Budget
    19→//!
    20→//! ## Usage
    21→//!
    22→//! ```no_run
    23→//! use forge_worker::router::{Router, RouterConfig, TaskMetadata};
    24→//! use forge_core::types::{Priority, WorkerTier};
    25→//!
    26→//! // Create router with default configuration
    27→//! let mut router = Router::new();
    28→//!
    29→//! // Create task metadata
    30→//! let task = TaskMetadata {
    31→//!     bead_id: "fg-123".to_string(),
    32→//!     priority: Priority::P0,
    33→//!     complexity_score: Some(85),
    34→//!     labels: vec!["architecture".to_string()],
    35→//!     requires_reasoning: true,
    36→//!     estimated_tokens: Some(5000),
    37→//! };
    38→//!
    39→//! // Get routing decision
    40→//! let decision = router.route(&task).unwrap();
    41→//! println!("Routed to {} ({})", decision.model_id, decision.tier);
    42→//!
    43→//! // Check fallback if needed
    44→//! if !decision.is_available {
    45→//!     let fallback = router.fallback(&decision).unwrap();
    46→//!     println!("Falling back to {}", fallback.model_id);
    47→//! }
    48→//! ```
    49→
    50→use chrono::{DateTime, Utc};
    51→use forge_core::types::{Priority, WorkerTier};
    52→use serde::{Deserialize, Serialize};
    53→use std::collections::HashMap;
    54→use tracing::{debug, info, warn};
    55→
    56→/// Default fallback timeout in seconds.
    57→const DEFAULT_FALLBACK_TIMEOUT_SECS: u64 = 5;
    58→
    59→/// Maximum models to track per tier (reserved for future validation).
    60→#[allow(dead_code)]
    61→const MAX_MODELS_PER_TIER: usize = 10;
    62→
    63→/// Configuration for the routing engine.
    64→#[derive(Debug, Clone, Serialize, Deserialize)]
    65→pub struct RouterConfig {
    66→    /// Enable subscription quota preference
    67→    pub prefer_subscription: bool,
    68→
    69→    /// Fallback timeout in seconds
    70→    pub fallback_timeout_secs: u64,
    71→
    72→    /// Enable load balancing across same-tier models
    73→    pub enable_load_balancing: bool,
    74→
    75→    /// Premium tier models
    76→    pub premium_models: Vec<ModelConfig>,
    77→
    78→    /// Standard tier models
    79→    pub standard_models: Vec<ModelConfig>,
    80→
    81→    /// Budget tier models
    82→    pub budget_models: Vec<ModelConfig>,
    83→}
    84→
    85→impl Default for RouterConfig {
    86→    fn default() -> Self {
    87→        Self {
    88→            prefer_subscription: true,
    89→            fallback_timeout_secs: DEFAULT_FALLBACK_TIMEOUT_SECS,
    90→            enable_load_balancing: true,
    91→            premium_models: vec![
    92→                ModelConfig::new("claude-opus-4", "Claude Opus 4", true),
    93→                ModelConfig::new("o1", "OpenAI O1", false),
    94→                ModelConfig::new("glm-5", "GLM-5", true),
    95→            ],
    96→            standard_models: vec![
    97→                ModelConfig::new("claude-sonnet-4", "Claude Sonnet 4", true),
    98→                ModelConfig::new("gpt-4", "GPT-4", false),
    99→                ModelConfig::new("qwen-2.5", "Qwen 2.5", false),
   100→            ],
   101→            budget_models: vec![
   102→                ModelConfig::new("claude-haiku-4", "Claude Haiku 4", true),
   103→                ModelConfig::new("gpt-3.5", "GPT-3.5", false),
   104→                ModelConfig::new("deepseek-coder", "DeepSeek Coder", false),
   105→            ],
   106→        }
   107→    }
   108→}
   109→
   110→impl RouterConfig {
   111→    /// Create a new router configuration with defaults.
   112→    pub fn new() -> Self {
   113→        Self::default()
   114→    }
   115→
   116→    /// Get models for a specific tier.
   117→    pub fn models_for_tier(&self, tier: WorkerTier) -> &[ModelConfig] {
   118→        match tier {
   119→            WorkerTier::Premium => &self.premium_models,
   120→            WorkerTier::Standard => &self.standard_models,
   121→            WorkerTier::Budget => &self.budget_models,
   122→        }
   123→    }
   124→
   125→    /// Load configuration from a YAML file.
   126→    pub fn from_yaml(path: &std::path::Path) -> Result<Self, RouterError> {
   127→        let content = std::fs::read_to_string(path)
   128→            .map_err(|e| RouterError::ConfigLoad {
   129→                path: path.to_path_buf(),
   130→                source: e,
   131→            })?;
   132→        let config: Self = serde_yaml::from_str(&content)
   133→            .map_err(|e| RouterError::ConfigParse {
   134→                message: e.to_string(),
   135→            })?;
   136→        config.validate()?;
   137→        Ok(config)
   138→    }
   139→
   140→    /// Validate the configuration.
   141→    pub fn validate(&self) -> Result<(), RouterError> {
   142→        if self.premium_models.is_empty() {
   143→            return Err(RouterError::ConfigValidation {
   144→                message: "At least one premium model is required".to_string(),
   145→            });
   146→        }
   147→        if self.standard_models.is_empty() {
   148→            return Err(RouterError::ConfigValidation {
   149→                message: "At least one standard model is required".to_string(),
   150→            });
   151→        }
   152→        if self.budget_models.is_empty() {
   153→            return Err(RouterError::ConfigValidation {
   154→                message: "At least one budget model is required".to_string(),
   155→            });
   156→        }
   157→        Ok(())
   158→    }
   159→}
   160→
   161→/// Configuration for a single model.
   162→#[derive(Debug, Clone, Serialize, Deserialize)]
   163→pub struct ModelConfig {
   164→    /// Model identifier (e.g., "claude-sonnet-4")
   165→    pub id: String,
   166→
   167→    /// Display name
   168→    pub name: String,
   169→
   170→    /// Whether this model has subscription quota
   171→    pub has_subscription: bool,
   172→
   173→    /// Maximum tokens per request
   174→    #[serde(default = "default_max_tokens")]
   175→    pub max_tokens: u32,
   176→
   177→    /// Cost per million input tokens in USD
   178→    #[serde(default)]
   179→    pub cost_per_million_input: f64,
   180→
   181→    /// Cost per million output tokens in USD
   182→    #[serde(default)]
   183→    pub cost_per_million_output: f64,
   184→}
   185→
   186→fn default_max_tokens() -> u32 {
   187→    128000
   188→}
   189→
   190→impl ModelConfig {
   191→    /// Create a new model configuration.
   192→    pub fn new(id: impl Into<String>, name: impl Into<String>, has_subscription: bool) -> Self {
   193→        Self {
   194→            id: id.into(),
   195→            name: name.into(),
   196→            has_subscription,
   197→            max_tokens: default_max_tokens(),
   198→            cost_per_million_input: 0.0,
   199→            cost_per_million_output: 0.0,
   200→        }
   201→    }
   202→
   203→    /// Set the maximum tokens.
   204→    pub fn with_max_tokens(mut self, max_tokens: u32) -> Self {
   205→        self.max_tokens = max_tokens;
   206→        self
   207→    }
   208→
   209→    /// Set the costs.
   210→    pub fn with_costs(mut self, input: f64, output: f64) -> Self {
   211→        self.cost_per_million_input = input;
   212→        self.cost_per_million_output = output;
   213→        self
   214→    }
   215→}
   216→
   217→/// Subscription quota status for a model.
   218→#[derive(Debug, Clone, Default)]
   219→pub struct SubscriptionQuota {
   220→    /// Total quota in tokens
   221→    pub total_tokens: u64,
   222→
   223→    /// Used tokens
   224→    pub used_tokens: u64,
   225→
   226→    /// Quota reset time (for use-or-lose subscriptions)
   227→    pub reset_at: Option<DateTime<Utc>>,
   228→}
   229→
   230→impl SubscriptionQuota {
   231→    /// Create a new subscription quota.
   232→    pub fn new(total_tokens: u64, used_tokens: u64) -> Self {
   233→        Self {
   234→            total_tokens,
   235→            used_tokens,
   236→            reset_at: None,
   237→        }
   238→    }
   239→
   240→    /// Create with reset time.
   241→    pub fn with_reset(mut self, reset_at: DateTime<Utc>) -> Self {
   242→        self.reset_at = Some(reset_at);
   243→        self
   244→    }
   245→
   246→    /// Get remaining tokens.
   247→    pub fn remaining(&self) -> u64 {
   248→        self.total_tokens.saturating_sub(self.used_tokens)
   249→    }
   250→
   251→    /// Get usage percentage.
   252→    pub fn usage_percent(&self) -> f64 {
   253→        if self.total_tokens == 0 {
   254→            return 0.0;
   255→        }
   256→        (self.used_tokens as f64 / self.total_tokens as f64) * 100.0
   257→    }
   258→
   259→    /// Check if quota is urgent (should use before reset).
   260→    pub fn is_urgent(&self) -> bool {
   261→        if let Some(reset_at) = self.reset_at {
   262→            let now = Utc::now();
   263→            let time_until_reset = reset_at.signed_duration_since(now);
   264→            // Urgent if less than 24 hours until reset and still have quota
   265→            time_until_reset.num_hours() < 24 && self.remaining() > 0
   266→        } else {
   267→            false
   268→        }
   269→    }
   270→
   271→    /// Check if quota is available.
   272→    pub fn is_available(&self) -> bool {
   273→        self.remaining() > 0
   274→    }
   275→}
