   314→/// Metadata about a task for routing decisions.
   315→#[derive(Debug, Clone)]
   316→pub struct TaskMetadata {
   317→    /// Bead/task ID
   318→    pub bead_id: String,
   319→
   320→    /// Task priority
   321→    pub priority: Priority,
   322→
   323→    /// Optional complexity score (0-100)
   324→    pub complexity_score: Option<u32>,
   325→
   326→    /// Task labels
   327→    pub labels: Vec<String>,
   328→
   329→    /// Whether the task requires complex reasoning
   330→    pub requires_reasoning: bool,
   331→
   332→    /// Estimated token count
   333→    pub estimated_tokens: Option<u64>,
   334→}
   335→
   336→impl TaskMetadata {
   337→    /// Create new task metadata.
   338→    pub fn new(bead_id: impl Into<String>, priority: Priority) -> Self {
   339→        Self {
   340→            bead_id: bead_id.into(),
   341→            priority,
   342→            complexity_score: None,
   343→            labels: Vec::new(),
   344→            requires_reasoning: false,
   345→            estimated_tokens: None,
   346→        }
   347→    }
   348→
   349→    /// Set complexity score.
   350→    pub fn with_complexity(mut self, score: u32) -> Self {
   351→        self.complexity_score = Some(score.min(100));
   352→        self
   353→    }
   354→
   355→    /// Add labels.
   356→    pub fn with_labels(mut self, labels: Vec<String>) -> Self {
   357→        self.labels = labels;
   358→        self
   359→    }
   360→
   361→    /// Set requires reasoning flag.
   362→    pub fn with_reasoning(mut self, requires: bool) -> Self {
   363→        self.requires_reasoning = requires;
   364→        self
   365→    }
   366→
   367→    /// Set estimated tokens.
   368→    pub fn with_estimated_tokens(mut self, tokens: u64) -> Self {
   369→        self.estimated_tokens = Some(tokens);
   370→        self
   371→    }
   372→
   373→    /// Determine the recommended tier based on task metadata.
   374→    pub fn recommended_tier(&self) -> WorkerTier {
   375→        // Start with priority-based recommendation
   376→        let base_tier = self.priority.recommended_tier();
   377→
   378→        // Upgrade tier if complex reasoning is required
   379→        if self.requires_reasoning {
   380→            return WorkerTier::Premium;
   381→        }
   382→
   383→        // Upgrade tier if complexity score is high
   384→        if let Some(score) = self.complexity_score {
   385→            if score >= 80 {
   386→                return WorkerTier::Premium;
   387→            } else if score >= 50 && base_tier == WorkerTier::Budget {
   388→                return WorkerTier::Standard;
   389→            }
   390→        }
   391→
   392→        // Check for special labels
   393→        let label_lower: Vec<String> = self.labels.iter().map(|l| l.to_lowercase()).collect();
   394→        if label_lower.iter().any(|l| l == "architecture" || l == "critical") {
   395→            return WorkerTier::Premium;
   396→        }
   397→        if label_lower.iter().any(|l| l == "complex") {
   398→            return WorkerTier::Standard;
   399→        }
   400→
   401→        base_tier
   402→    }
   403→}
