   436→/// Reason for a routing decision.
   437→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize)]
   438→#[serde(rename_all = "kebab-case")]
   439→pub enum RoutingReason {
   440→    /// Priority-based routing
   441→    PriorityBased,
   442→
   443→    /// Complexity-based routing
   444→    ComplexityBased,
   445→
   446→    /// Subscription quota preference
   447→    SubscriptionPreference,
   448→
   449→    /// Load balancing
   450→    LoadBalancing,
   451→
   452→    /// Fallback from higher tier
   453→    Fallback,
   454→
   455→    /// Label-based routing
   456→    LabelBased,
   457→
   458→    /// Default routing
   459→    Default,
   460→}
   461→
   462→impl std::fmt::Display for RoutingReason {
   463→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
   464→        match self {
   465→            Self::PriorityBased => write!(f, "priority-based"),
   466→            Self::ComplexityBased => write!(f, "complexity-based"),
   467→            Self::SubscriptionPreference => write!(f, "subscription-preference"),
   468→            Self::LoadBalancing => write!(f, "load-balancing"),
   469→            Self::Fallback => write!(f, "fallback"),
   470→            Self::LabelBased => write!(f, "label-based"),
   471→            Self::Default => write!(f, "default"),
   472→        }
   473→    }
   474→}
