   489→/// The multi-model routing engine.
   490→#[derive(Debug)]
   491→pub struct Router {
   492→    /// Configuration
   493→    config: RouterConfig,
   494→
   495→    /// Subscription quotas per model
   496→    quotas: HashMap<String, SubscriptionQuota>,
   497→
   498→    /// Model availability status
   499→    availability: HashMap<String, ModelAvailability>,
   500→
   501→    /// Routing history for analytics (last 1000 decisions)
   502→    history: Vec<RoutingDecision>,
   503→
   504→    /// Load balancing counters per model
   505→    load_counters: HashMap<String, u64>,
   506→}
   507→
   508→impl Default for Router {
   509→    fn default() -> Self {
   510→        Self::new()
   511→    }
   512→}
   513→
   514→impl Router {
   515→    /// Create a new router with default configuration.
   516→    pub fn new() -> Self {
   517→        Self::with_config(RouterConfig::default())
   518→    }
   519→
   520→    /// Create a router with custom configuration.
   521→    pub fn with_config(config: RouterConfig) -> Self {
   522→        let mut router = Self {
   523→            config,
   524→            quotas: HashMap::new(),
   525→            availability: HashMap::new(),
   526→            history: Vec::with_capacity(1000),
   527→            load_counters: HashMap::new(),
   528→        };
   529→        router.initialize_model_states();
   530→        router
   531→    }
   532→
   533→    /// Initialize model states from configuration.
   534→    fn initialize_model_states(&mut self) {
   535→        let all_models: Vec<_> = self.config.premium_models.iter()
   536→            .chain(self.config.standard_models.iter())
   537→            .chain(self.config.budget_models.iter())
   538→            .collect();
   539→
   540→        for model in all_models {
   541→            self.availability.insert(
   542→                model.id.clone(),
   543→                ModelAvailability::new(&model.id, true),
   544→            );
   545→            self.load_counters.insert(model.id.clone(), 0);
   546→        }
   547→    }
   548→
   549→    /// Get the current configuration.
   550→    pub fn config(&self) -> &RouterConfig {
   551→        &self.config
   552→    }
   553→
   554→    /// Update subscription quota for a model.
   555→    pub fn update_quota(&mut self, model_id: impl Into<String>, quota: SubscriptionQuota) {
   556→        self.quotas.insert(model_id.into(), quota);
   557→    }
   558→
   559→    /// Update model availability.
   560→    pub fn update_availability(&mut self, availability: ModelAvailability) {
   561→        self.availability.insert(availability.model_id.clone(), availability);
   562→    }
   563→
   564→    /// Get all models for a tier.
   565→    fn get_tier_models(&self, tier: WorkerTier) -> Vec<&ModelConfig> {
   566→        self.config.models_for_tier(tier).iter().collect()
   567→    }
   568→
   569→    /// Route a task to the best available model.
   570→    pub fn route(&mut self, task: &TaskMetadata) -> Result<RoutingDecision, RouterError> {
   571→        let recommended_tier = task.recommended_tier();
   572→        debug!(
   573→            bead_id = %task.bead_id,
   574→            priority = ?task.priority,
   575→            recommended_tier = ?recommended_tier,
   576→            "Routing task"
   577→        );
   578→
   579→        // Try to find best model in recommended tier
   580→        let mut decision = self.select_model(task, recommended_tier)?;
   581→
   582→        // Build fallback chain and add to decision
   583→        decision.fallback_chain = self.build_fallback_chain(decision.tier);
   584→
   585→        // Record in history
   586→        self.record_decision(&decision);
   587→
   588→        info!(
   589→            bead_id = %task.bead_id,
   590→            model = %decision.model_id,
   591→            tier = ?decision.tier,
   592→            reason = %decision.reason,
   593→            "Routing decision made"
   594→        );
   595→
   596→        Ok(decision)
   597→    }
   598→
   599→    /// Select a model from a specific tier.
   600→    fn select_model(
   601→        &mut self,
   602→        task: &TaskMetadata,
   603→        tier: WorkerTier,
   604→    ) -> Result<RoutingDecision, RouterError> {
   605→        let models = self.get_tier_models(tier);
   606→        if models.is_empty() {
   607→            return Err(RouterError::NoModelsAvailable { tier });
   608→        }
   609→
   610→        // Score each model and collect results
   611→        let scored_models: Vec<_> = models
   612→            .iter()
   613→            .map(|model| {
   614→                let score = self.score_model(model, task);
   615→                (*model, score)
   616→            })
   617→            .collect();
   618→
   619→        // Sort by score (highest first)
   620→        let best = scored_models
   621→            .into_iter()
   622→            .max_by_key(|(_, score)| *score as u64)
   623→            .map(|(model, _)| model)
   624→            .ok_or_else(|| RouterError::NoModelsAvailable { tier })?;
   625→
   626→        // Extract all data we need from best before mutating
   627→        let model_id = best.id.clone();
   628→        let model_name = best.name.clone();
   629→        let has_subscription = best.has_subscription;
   630→
   631→        // Check availability
   632→        let is_available = self
   633→            .availability
   634→            .get(&model_id)
   635→            .map(|a| a.is_available)
   636→            .unwrap_or(true);
   637→
   638→        // Determine reason
   639→        let reason = self.determine_reason(best, task, tier);
   640→
   641→        // Update load counter for load balancing
   642→        if self.config.enable_load_balancing {
   643→            *self.load_counters.entry(model_id.clone()).or_insert(0) += 1;
   644→        }
   645→
   646→        Ok(RoutingDecision {
   647→            model_id,
   648→            model_name,
   649→            tier,
   650→            is_available,
   651→            uses_subscription: has_subscription,
   652→            reason,
   653→            decided_at: Utc::now(),
   654→            fallback_chain: Vec::new(), // Will be filled in by route()
   655→            task_id: task.bead_id.clone(),
   656→        })
   657→    }
   658→
   659→    /// Score a model for selection.
   660→    fn score_model(&self, model: &ModelConfig, _task: &TaskMetadata) -> f64 {
   661→        let mut score = 100.0;
   662→
   663→        // Prefer subscription models if enabled
   664→        if self.config.prefer_subscription && model.has_subscription {
   665→            // Check if quota is available
   666→            if let Some(quota) = self.quotas.get(&model.id) {
   667→                if quota.is_available() {
   668→                    score += 20.0;
   669→                    // Bonus for urgent quota (use-or-lose)
   670→                    if quota.is_urgent() {
   671→                        score += 15.0;
   672→                    }
   673→                }
   674→            } else {
   675→                // Has subscription but no quota tracked - still prefer
   676→                score += 10.0;
   677→            }
   678→        }
   679→
   680→        // Load balancing penalty
   681→        if self.config.enable_load_balancing {
   682→            let load = self.load_counters.get(&model.id).copied().unwrap_or(0);
   683→            score -= (load as f64) * 0.5;
   684→        }
   685→
   686→        // Availability penalty
   687→        if let Some(avail) = self.availability.get(&model.id) {
   688→            if !avail.is_available {
   689→                score -= 100.0;
   690→            }
   691→            // Latency penalty
   692→            if let Some(latency) = avail.avg_latency_ms {
   693→                if latency > 5000 {
   694→                    score -= 10.0;
   695→                }
   696→            }
   697→        }
   698→
   699→        score.max(0.0)
   700→    }
   701→
   702→    /// Determine the routing reason.
   703→    fn determine_reason(&self, model: &ModelConfig, task: &TaskMetadata, tier: WorkerTier) -> RoutingReason {
   704→        // Check subscription preference first
   705→        if self.config.prefer_subscription && model.has_subscription {
   706→            if let Some(quota) = self.quotas.get(&model.id) {
   707→                if quota.is_urgent() {
   708→                    return RoutingReason::SubscriptionPreference;
   709→                }
   710→            }
   711→        }
   712→
   713→        // Check complexity-based
   714→        if task.complexity_score.is_some() || task.requires_reasoning {
   715→            return RoutingReason::ComplexityBased;
   716→        }
   717→
   718→        // Check label-based
   719→        if !task.labels.is_empty() {
   720→            return RoutingReason::LabelBased;
   721→        }
   722→
   723→        // Check if load balancing was applied
   724→        if self.config.enable_load_balancing {
   725→            let load = self.load_counters.get(&model.id).copied().unwrap_or(0);
   726→            if load > 0 {
   727→                return RoutingReason::LoadBalancing;
   728→            }
   729→        }
   730→
   731→        // Default to priority-based
   732→        if tier == task.priority.recommended_tier() {
   733→            RoutingReason::PriorityBased
   734→        } else {
   735→            RoutingReason::Default
   736→        }
   737→    }
   738→
   739→    /// Build the fallback chain for a decision.
   740→    fn build_fallback_chain(&self, current_tier: WorkerTier) -> Vec<FallbackOption> {
   741→        let mut chain = Vec::new();
   742→
   743→        match current_tier {
   744→            WorkerTier::Premium => {
   745→                // Fallback to standard, then budget
   746→                for model in &self.config.standard_models {
   747→                    chain.push(FallbackOption {
   748→                        model_id: model.id.clone(),
   749→                        tier: WorkerTier::Standard,
   750→                        reason: "Premium tier unavailable".to_string(),
   751→                    });
   752→                }
   753→                for model in &self.config.budget_models {
   754→                    chain.push(FallbackOption {
   755→                        model_id: model.id.clone(),
   756→                        tier: WorkerTier::Budget,
   757→                        reason: "Premium and standard tiers unavailable".to_string(),
   758→                    });
   759→                }
   760→            }
   761→            WorkerTier::Standard => {
   762→                // Fallback to budget only
   763→                for model in &self.config.budget_models {
   764→                    chain.push(FallbackOption {
   765→                        model_id: model.id.clone(),
   766→                        tier: WorkerTier::Budget,
   767→                        reason: "Standard tier unavailable".to_string(),
   768→                    });
   769→                }
   770→            }
   771→            WorkerTier::Budget => {
   772→                // No fallback from budget
   773→            }
   774→        }
   775→
   776→        chain
   777→    }
   778→
   779→    /// Get fallback decision when primary is unavailable.
   780→    pub fn fallback(&mut self, decision: &RoutingDecision) -> Result<RoutingDecision, RouterError> {
   781→        if decision.fallback_chain.is_empty() {
   782→            return Err(RouterError::NoFallbackAvailable {
   783→                model_id: decision.model_id.clone(),
   784→            });
   785→        }
   786→
   787→        // Find first available fallback
   788→        for fallback in &decision.fallback_chain {
   789→            if let Some(avail) = self.availability.get(&fallback.model_id) {
   790→                if avail.is_available {
   791→                    let model = self
   792→                        .config
   793→                        .models_for_tier(fallback.tier)
   794→                        .iter()
   795→                        .find(|m| m.id == fallback.model_id);
   796→
   797→                    if let Some(model) = model {
   798→                        let new_decision = RoutingDecision {
   799→                            model_id: model.id.clone(),
   800→                            model_name: model.name.clone(),
   801→                            tier: fallback.tier,
   802→                            is_available: true,
   803→                            uses_subscription: model.has_subscription,
   804→                            reason: RoutingReason::Fallback,
   805→                            decided_at: Utc::now(),
   806→                            fallback_chain: self.build_fallback_chain(fallback.tier),
   807→                            task_id: decision.task_id.clone(),
   808→                        };
   809→
   810→                        self.record_decision(&new_decision);
   811→
   812→                        warn!(
   813→                            from_model = %decision.model_id,
   814→                            to_model = %new_decision.model_id,
   815→                            "Falling back to alternative model"
   816→                        );
   817→
   818→                        return Ok(new_decision);
   819→                    }
   820→                }
   821→            }
   822→        }
   823→
   824→        Err(RouterError::NoFallbackAvailable {
   825→            model_id: decision.model_id.clone(),
   826→        })
   827→    }
   828→
   829→    /// Record a routing decision in history.
   830→    fn record_decision(&mut self, decision: &RoutingDecision) {
   831→        self.history.push(decision.clone());
   832→
   833→        // Keep only last 1000 decisions
   834→        if self.history.len() > 1000 {
   835→            self.history.remove(0);
   836→        }
   837→    }
   838→
   839→    /// Get routing history.
   840→    pub fn history(&self) -> &[RoutingDecision] {
   841→        &self.history
   842→    }
   843→
   844→    /// Get routing statistics.
   845→    pub fn stats(&self) -> RouterStats {
   846→        let mut by_tier = HashMap::new();
   847→        let mut by_model = HashMap::new();
   848→        let mut by_reason = HashMap::new();
   849→
   850→        for decision in &self.history {
   851→            *by_tier.entry(decision.tier).or_insert(0) += 1;
   852→            *by_model.entry(decision.model_id.clone()).or_insert(0) += 1;
   853→            *by_reason.entry(decision.reason).or_insert(0) += 1;
   854→        }
   855→
   856→        RouterStats {
   857→            total_decisions: self.history.len(),
   858→            by_tier,
   859→            by_model,
   860→            by_reason,
   861→        }
   862→    }
   863→
   864→    /// Clear routing history.
   865→    pub fn clear_history(&mut self) {
   866→        self.history.clear();
   867→    }
   868→
   869→    /// Check if a model is available for routing.
   870→    pub fn is_model_available(&self, model_id: &str) -> bool {
   871→        self.availability
   872→            .get(model_id)
   873→            .map(|a| a.is_available)
   874→            .unwrap_or(false)
   875→    }
   876→
   877→    /// Get all available models for a tier.
   878→    pub fn available_models(&self, tier: WorkerTier) -> Vec<&ModelConfig> {
   879→        self.config
   880→            .models_for_tier(tier)
   881→            .iter()
   882→            .filter(|m| self.is_model_available(&m.id))
   883→            .collect()
   884→    }
   885→
   886→    /// Check health of all models.
   887→    pub fn health_check(&self) -> HashMap<String, ModelHealth> {
   888→        let mut health = HashMap::new();
   889→
   890→        for (model_id, avail) in &self.availability {
   891→            let quota = self.quotas.get(model_id);
   892→            health.insert(
   893→                model_id.clone(),
   894→                ModelHealth {
   895→                    is_available: avail.is_available,
   896→                    active_workers: avail.active_workers,
   897→                    avg_latency_ms: avail.avg_latency_ms,
   898→                    last_error: avail.last_error.clone(),
   899→                    quota_remaining: quota.map(|q| q.remaining()),
   900→                    quota_urgent: quota.map(|q| q.is_urgent()).unwrap_or(false),
   901→                },
   902→            );
   903→        }
   904→
   905→        health
   906→    }
   907→}
