    27→/// Budget alert severity levels.
    28→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    29→pub enum BudgetAlertLevel {
    30→    /// Under budget - everything is fine
    31→    Normal,
    32→    /// Approaching budget threshold (70-90%)
    33→    Warning,
    34→    /// At or exceeding budget (90%+)
    35→    Critical,
    36→    /// Budget exceeded
    37→    Exceeded,
    38→}
    39→
    40→impl BudgetAlertLevel {
    41→    /// Get the color for this alert level.
    42→    pub fn color(&self) -> Color {
    43→        match self {
    44→            BudgetAlertLevel::Normal => Color::Green,
    45→            BudgetAlertLevel::Warning => Color::Yellow,
    46→            BudgetAlertLevel::Critical => Color::LightRed,
    47→            BudgetAlertLevel::Exceeded => Color::Red,
    48→        }
    49→    }
    50→
    51→    /// Get icon for this alert level.
    52→    pub fn icon(&self) -> &'static str {
    53→        match self {
    54→            BudgetAlertLevel::Normal => "✓",
    55→            BudgetAlertLevel::Warning => "⚠",
    56→            BudgetAlertLevel::Critical => "⚠",
    57→            BudgetAlertLevel::Exceeded => "✗",
    58→        }
    59→    }
    60→
    61→    /// Get description for this alert level.
    62→    pub fn description(&self) -> &'static str {
    63→        match self {
    64→            BudgetAlertLevel::Normal => "On Track",
    65→            BudgetAlertLevel::Warning => "Approaching Limit",
    66→            BudgetAlertLevel::Critical => "Near Limit",
    67→            BudgetAlertLevel::Exceeded => "Over Budget",
    68→        }
    69→    }
    70→
    71→    /// Determine alert level from usage percentage.
    72→    pub fn from_percentage(pct: f64) -> Self {
    73→        if pct >= 100.0 {
    74→            BudgetAlertLevel::Exceeded
    75→        } else if pct >= 90.0 {
    76→            BudgetAlertLevel::Critical
    77→        } else if pct >= 70.0 {
    78→            BudgetAlertLevel::Warning
    79→        } else {
    80→            BudgetAlertLevel::Normal
    81→        }
    82→    }
    83→}
