   373→/// Renders a sparkline from a series of values.
   374→pub fn render_sparkline(values: &[f64], width: usize) -> String {
   375→    if values.is_empty() {
   376→        return " ".repeat(width);
   377→    }
   378→
   379→    let blocks = ['▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
   380→    let max = values.iter().cloned().fold(0.0_f64, f64::max);
   381→    let min = values.iter().cloned().fold(f64::MAX, f64::min);
   382→    let range = max - min;
   383→
   384→    // Sample values to fit width
   385→    let step = values.len() as f64 / width as f64;
   386→    let mut result = String::with_capacity(width);
   387→
   388→    for i in 0..width {
   389→        let idx = ((i as f64) * step).min(values.len() as f64 - 1.0) as usize;
   390→        let val = values[idx];
   391→
   392→        let normalized = if range > 0.0 {
   393→            ((val - min) / range).clamp(0.0, 1.0)
   394→        } else {
   395→            0.5
   396→        };
   397→
   398→        let block_idx = ((normalized * 7.0).round() as usize).min(7);
   399→        result.push(blocks[block_idx]);
   400→    }
   401→
   402→    result
   403→}
   404→
   405→/// Renders a horizontal bar chart.
   406→pub fn render_bar(
   407→    value: f64,
   408→    max: f64,
   409→    width: usize,
   410→    filled_char: char,
   411→    empty_char: char,
   412→) -> String {
   413→    let pct = if max > 0.0 {
   414→        (value / max).clamp(0.0, 1.0)
   415→    } else {
   416→        0.0
   417→    };
   418→    let filled = (pct * width as f64).round() as usize;
   419→    let empty = width.saturating_sub(filled);
   420→
   421→    format!(
   422→        "{}{}",
   423→        filled_char.to_string().repeat(filled),
   424→        empty_char.to_string().repeat(empty)
   425→    )
   426→}
