   475→/// Cost analytics panel widget.
   476→pub struct CostPanel<'a> {
   477→    data: &'a CostPanelData,
   478→    focused: bool,
   479→}
   480→
   481→impl<'a> CostPanel<'a> {
   482→    /// Create a new cost panel.
   483→    pub fn new(data: &'a CostPanelData) -> Self {
   484→        Self {
   485→            data,
   486→            focused: false,
   487→        }
   488→    }
   489→
   490→    /// Set focus state.
   491→    pub fn focused(mut self, focused: bool) -> Self {
   492→        self.focused = focused;
   493→        self
   494→    }
   495→
   496→    /// Render the summary section.
   497→    fn render_summary(&self, area: Rect, buf: &mut Buffer) {
   498→        let mut lines = Vec::new();
   499→
   500→        // Today's costs with alert
   501→        let daily_alert = self.data.daily_alert();
   502→        let today_line = Line::from(vec![
   503→            Span::raw("Today: "),
   504→            Span::styled(
   505→                format_usd(self.data.today_total()),
   506→                Style::default()
   507→                    .fg(daily_alert.color())
   508→                    .add_modifier(Modifier::BOLD),
   509→            ),
   510→            Span::raw(" / "),
   511→            Span::styled(
   512→                format_usd(self.data.budget.effective_daily_limit()),
   513→                Style::default().fg(Color::Gray),
   514→            ),
   515→            Span::raw(" "),
   516→            Span::styled(
   517→                format!("{} {}", daily_alert.icon(), daily_alert.description()),
   518→                Style::default().fg(daily_alert.color()),
   519→            ),
   520→        ]);
   521→        lines.push(today_line);
