   887→
   888→        // Show top workers (limit to fit area)
   889→        let worker_limit = (area.height.saturating_sub(4) as usize).min(8);
   890→        for worker in self.data.worker_costs.iter().take(worker_limit) {
   891→            // Truncate worker ID
