   903→            } else {
   904→                Color::Green
   905→            };
   906→
   907→            // Expense indicator
   908→            let indicator = if worker.is_expensive { "⚠ " } else { "  " };
   909→
   910→            // Task info
   911→            let task = worker
   912→                .bead_id
   913→                .as_ref()
   914→                .map(|t| {
