   964→impl Widget for CostPanel<'_> {
   965→    fn render(self, area: Rect, buf: &mut Buffer) {
   966→        // Enhanced focus indicator: "▶" arrow for focused (clearer than diamond), "▪" for unfocused
   967→        let focus_icon = if self.focused { "▶" } else { "▪" };
   968→
   969→        // Border type: Double border for focused (highly visible), Normal for unfocused
   970→        let border_type = if self.focused {
   971→            BorderType::Double
   972→        } else {
   973→            BorderType::Plain
   974→        };
   975→
   976→        // Border style: bright cyan with bold for focused, dim for unfocused
   977→        let border_style = if self.focused {
   978→            Style::default()
   979→                .fg(Color::Cyan)
   980→                .add_modifier(Modifier::BOLD)
   981→        } else {
   982→            Style::default().fg(Color::DarkGray)
   983→        };
   984→
   985→        // Title style: bold + underlined for focused, dim for unfocused
   986→        let title_style = if self.focused {
   987→            Style::default()
   988→                .fg(Color::Cyan)
   989→                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
   990→        } else {
   991→            Style::default().fg(Color::Rgb(80, 80, 80))
   992→        };
   993→
   994→        let block = Block::default()
   995→            .borders(Borders::ALL)
   996→            .border_type(border_type)
   997→            .border_style(border_style)
   998→            .title(Span::styled(
   999→                format!(" {} Cost Analytics ", focus_icon),
  1000→                title_style,
  1001→            ));
  1002→
  1003→        let inner = block.inner(area);
  1004→        block.render(area, buf);
  1005→
  1006→        // Handle special states
  1007→        if self.data.is_loading {
  1008→            let loading =
  1009→                Paragraph::new("Loading cost data...").style(Style::default().fg(Color::Yellow));
  1010→            loading.render(inner, buf);
  1011→            return;
  1012→        }
  1013→
  1014→        if let Some(ref error) = self.data.error {
  1015→            let err =
  1016→                Paragraph::new(format!("Error: {}", error)).style(Style::default().fg(Color::Red));
  1017→            err.render(inner, buf);
  1018→            return;
  1019→        }
  1020→
  1021→        if !self.data.has_data() {
  1022→            let no_data = Paragraph::new(
  1023→                "No cost data available.\n\n\
  1024→                 Cost tracking requires:\n\
  1025→                 - forge-cost database initialized\n\
  1026→                 - Worker logs being parsed\n\n\
  1027→                 Run: forge costs init",
  1028→            )
  1029→            .style(Style::default().fg(Color::Gray));
  1030→            no_data.render(inner, buf);
  1031→            return;
  1032→        }
  1033→
  1034→        // Layout: Summary | Worker Costs | Model Table | Trend | Recommendations
  1035→        let rec_height = if self.data.has_recommendations() { 5 } else { 0 };
  1036→        let worker_height = if self.data.has_worker_costs() { 8 } else { 0 };
  1037→        let layout = Layout::default()
  1038→            .direction(Direction::Vertical)
  1039→            .constraints([
  1040→                Constraint::Length(11),     // Summary (increased for week line)
  1041→                Constraint::Length(worker_height), // Worker costs
  1042→                Constraint::Min(5),         // Model table
  1043→                Constraint::Length(4),      // Trend sparkline
  1044→                Constraint::Length(rec_height), // Recommendations
  1045→            ])
  1046→            .split(inner);
  1047→
  1048→        self.render_summary(layout[0], buf);
  1049→        if worker_height > 0 {
  1050→            self.render_worker_costs(layout[1], buf);
  1051→        }
  1052→        self.render_model_table(layout[2], buf);
  1053→        self.render_trend(layout[3], buf);
  1054→        if rec_height > 0 {
  1055→            self.render_recommendations(layout[4], buf);
  1056→        }
  1057→    }
  1058→}
